html:xslt.xsl:template:
			body {
					background-color: #FFFFFF;

					PADDING-RIGHT: 0px;
					PADDING-LEFT: 0px;
					PADDING-BOTTOM: 0px;
					MARGIN: 0px;
					BORDER-TOP-STYLE: none;
					PADDING-TOP: 0px;
					BORDER-RIGHT-STYLE: none;
					BORDER-LEFT-STYLE: none;
					BORDER-BOTTOM-STYLE: none;

					FONT-FAMILY: Arial, Helvetica, sans-serif;

				}

/******************************************************** TABLAS DETALLE */
.tabla_detail {
  table-layout: fixed;
  height: 100%;
  width: 100%;

  font-size: 11px;
  font-weight: normal;
  color: #303030;

  margin: 0px 0px 0px 0px;
  padding: 0;

  text-decoration: none;
}

.tabla_detail th {
  height: 28px;
  text-align: left;

  clear: none;
  font-size: 12px;
  font-weight: bold;
  color: #818181;
  text-decoration: none;
  background-color: #F7F7F7;
  border: 1px solid #c8c8c8;
  padding-left: 10px;
  padding-top: 5px;
  padding-bottom: 5px;
}

.tabla_detail div {
  clear: none;
  font-size: 11px;
  font-weight: normal;
  color: #303030;
  text-decoration: none;
  padding-top: 5px;
  padding-bottom: 8px;
  padding-left: 3px;

  overflow:auto;
  overflow-x:none;
  overflow-y:auto;
  height:100%;
  width:100%;

  scrollbar-highlight-color:#EAEAEA;
  scrollbar-darkshadow-color:#EAEAEA;
  scrollbar-track-color:#FAFAFA;
  scrollbar-face-color:#FAFAFA;
  scrollbar-base-color:#f7f7f7;

  scrollbar-arrow-color:#8FB8C4;
}

.tabla_noticia p {
  margin: 5px;
  padding: 0px;
}

/******************************************************** ESTILOS TEXTO */
.estilo1 {
  color: #3085b8;
}

.estilo1 a{
  font-size: 11px;
  font-weight: normal;
  color: #3085b8;
  text-decoration: none;
}
.estilo1 a:hover{
  font-size: 11px;
  font-weight: normal;
  color: #3085b8;
  text-decoration: underline;
}

.estilo2 {
  font-weight: normal;
  color: #3B6634;
}

.underline {
  border-bottom-width: 1px;
  border-bottom-style: solid;
  border-bottom-color: #C8C8C8;
}

.row_estilo_1{
  font-weight: normal;
  color: #3B6634;
}

.img_back {
  padding-left:40px;
  background-position: center left;
  background-repeat:no-repeat;
}

.img_back2 {
  padding-left:20px;
  background-position: center left;
  background-repeat:no-repeat;
}

/******************************************************** TITULOS */

.titu_1 {
  font-size: 11px;
  font-weight: bold;
  color: #3085b8;
}

.titu_2 {
  font-size: 14px;
  font-weight: bold;
}

.titu_3 {
  font-size: 11px;
  font-weight: bold;
  color: #A1A1A1;
}

.titu_4 {
  font-size: 11px;
  font-weight: bold;
  color: #3104B4;
}

.titu_5 {
  font-size: 11px;
  color: #E0313D;

  background-image: url(../../Images/Reports/RedBullet.gif);
  background-repeat: no-repeat;

  padding-left: 10px;
}


/* BOTONES ****************************************************************************************/

.boton {
  font-size: 11px;
  font-weight: normal;
  color: #0068a6;
  text-decoration: underline;
  cursor:pointer;
}

.boton:hover{
  font-size: 11px;
  font-weight: normal;
  color: #0068a6;
  text-decoration: underline;
  cursor:pointer;
}

.boton2_n {
  width:95px;
  height:20px;
  background-color:#f7f7f7;
  background-repeat: no-repeat;
  font-weight:bold;
  color: #3085b8;
  cursor:pointer;
}

.boton2_o {
  width:95px;
  height:20px;
  background-color: #E1EAEA;
  background-repeat: no-repeat;
  font-weight: bold;
  color: #2B75A0;
  cursor: pointer;
}























