head.script:

			function ChangeStyleSB (pObj, pOver) {
			var imgSrc = pObj.src;

			if (pOver)
				imgSrc = imgSrc.replace("_n.", "_o.");
			else
				imgSrc = imgSrc.replace("_o.", "_n.");

			pObj.src = imgSrc;
		}

		function ChangeStyleBut (pObj, pImg, pOver) {
			var objImg;
			var objTxt;

			if (pObj) {
				var typeTxt = typeof(pObj);

				if (typeTxt.toUpperCase() == "STRING")
					objTxt = document.getElementById(pObj);
				else 
					objTxt = pObj;

				var strCName = objTxt.className;

				if (pOver)
					strCName = strCName.replace("Button_n", "Button_o");
				else
					strCName = strCName.replace("Button_o", "Button_n");

				objTxt.className = strCName; 

           	}

			if (pImg) {
				var typeImg = typeof(pImg);

				if (typeImg.toUpperCase() == "STRING")
					objImg = document.getElementById(pImg);
				else 
					objImg = pImg;

				ChangeStyleSB(objImg, pOver);
           	}
		}
